#include<bits/stdc++.h>
using namespace std;
int n,m,f[41][5050],s[41],id[41],ans[41];
struct from
{
    int i,j;
}pre[41][5050];
struct node
{
    int v,id;
    bool operator<(const node&b)const
    {
        return v>b.v;
    }
}g[41];
void calc(from x,from fa)
{
    if(x.i==fa.i)
    {
        id[1]++;
        id[x.i+1]--;
    }
    else
    {
        id[x.i+1]++;
        id[fa.i+1]--;
    }
    if(x.i!=0)
    {
        calc(pre[x.i][x.j],x);
    }
}
int main()
{
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&g[i].v);
        g[i].id=i;
    }
    sort(g+1,g+1+n);
    for(int i=1;i<=n;i++)
    {
        s[i]=s[i-1]+g[i].v;
    }
    memset(f,0x3f,sizeof(f));
    f[0][0]=0;
    for(int i=1;i<=n;i++)
    {
        for(int j=i;j<=m;j++)
        {
            int tmp=f[i][j-i];
            pre[i][j]=(from){i,j-i};
            for(int k=0;k<i;k++)
            {
                int val=f[k][j-(i-k)]+k*(s[i]-s[k]);
                if(val<tmp)
                {
                    tmp=val;
                    pre[i][j]=(from){k,j-(i-k)};
                }
            }
            f[i][j]=min(f[i][j],tmp);
        }
    }
    printf("%d\n",f[n][m]);
    calc(pre[n][m],(from){n,m});
    for(int i=0;i<=n;i++)
    {
        id[i]+=id[i-1];
        if(i>0)
        {
            ans[g[i].id]=id[i];
        }
    }
    for(int i=1;i<=n;i++)
    {
        printf("%d ",ans[i]);
    }
    return 0;
}
